async (params, browser) => {
  // Open post page
  await browser.open(`${params.post_url}`)

  // Wait for post to load
  await browser.waitForSelector('h1, [class*=\'post-title\'], article', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract post details
  const post_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [class*="post-title"], [class*="headline"]'); const subtitleEl = document.querySelector('[class*="subtitle"], h2[class*="subtitle"]'); const authorEl = document.querySelector('[class*="author"] a, [class*="byline"] a, a[class*="author-name"]'); const newsletterEl = document.querySelector('[class*="publication-name"], [class*="pub-name"], a[class*="navbar-title"]'); const dateEl = document.querySelector('time, [class*="post-date"], [class*="date"]'); const likesEl = document.querySelector('[class*="like-count"], [class*="heart"] span, [class*="reaction-count"]'); const commentsEl = document.querySelector('[class*="comment-count"], a[href*="comments"] span, [class*="response-count"]'); const contentEls = document.querySelectorAll('[class*="body"] p, article p, [class*="post-content"] p'); let content = ''; for (let i = 0; i < contentEls.length; i++) { content += contentEls[i].textContent.trim() + '\n'; if (content.length > 2000) break; } const imgEl = document.querySelector('[class*="post"] img[src*="substackcdn"], article img, [class*="cover"] img'); const tagEls = document.querySelectorAll('[class*="tag"] a, [class*="topic"] a'); const tags = []; tagEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 50 && !tags.includes(t)) tags.push(t); }); return { title: titleEl ? titleEl.textContent.trim() : '', subtitle: subtitleEl ? subtitleEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', newsletter: newsletterEl ? newsletterEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', likes: likesEl ? likesEl.textContent.trim() : '', comments: commentsEl ? commentsEl.textContent.trim() : '', content_preview: content.substring(0, 2000), tags: tags.slice(0, 10), image: imgEl ? imgEl.getAttribute('src') : '', url: window.location.href }`)

  return post_data
}
